let myChartInstance = null; let allocationChartInstance = null; let marketChartInstance = null; let chartModal = null; let sellModal = null; let _notesModal = null; let currentBondIsin = null; let currentBondLabels = []; let currentBondPrices = []; let currentBondNkd = []; let currentBondYtm = []; let historyLoaded = false; let incomeData = {}; let currentPreviewPrice = null; let bondsData = []; let sortKey = null; let sortDir = 1; // 1 = ascending, -1 = descending function getCurrencySymbol(cur) { switch (cur) { case 'USD': return '$'; case 'CNY': return '¥'; case 'EUR': return '€'; case 'GLD': return 'г'; case 'RUB': default: return '₽'; } } var _todayStr = new Date().toISOString().split('T')[0]; document.getElementById('bondDate').value = _todayStr; document.addEventListener('DOMContentLoaded', () => { document.querySelectorAll('[data-bs-toggle="tooltip"]').forEach(el => { new bootstrap.Tooltip(el); }); }); async function openBondChart(isin) { currentBondIsin = isin; document.getElementById('chartModalIsinTitle').innerText = isin; if (!chartModal) chartModal = new bootstrap.Modal(document.getElementById('bondChartModal')); chartModal.show(); await loadBondChartData('month'); const buttons = document.querySelectorAll('#periodBtnGroup .btn'); buttons.forEach(btn => btn.classList.remove('active')); const defaultBtn = document.querySelector('#periodBtnGroup [data-period="month"]'); if (defaultBtn) defaultBtn.classList.add('active'); } async function loadBondChartData(period) { if (!currentBondIsin) return; const response = await fetch(`/api/bond_chart/${currentBondIsin}?range=${period}`); if (!response.ok) return; const resData = await response.json(); currentBondLabels = resData.labels || []; currentBondPrices = resData.data || []; currentBondNkd = resData.nkd || []; currentBondYtm = resData.ytm || []; const ctx = document.getElementById('marketBondChart').getContext('2d'); if (marketChartInstance) marketChartInstance.destroy(); marketChartInstance = new Chart(ctx, { type: 'line', data: { labels: currentBondLabels, datasets: [{ label: 'Рыночная стоимость (₽)', data: currentBondPrices, borderColor: '#0d6efd', backgroundColor: 'rgba(13, 110, 253, 0.04)', borderWidth: 2, fill: true, pointRadius: period === 'all' ? 0 : (period === 'day' || period === 'week' ? 5 : 2) }] }, options: { responsive: true, maintainAspectRatio: false, plugins: { tooltip: { callbacks: { label: ctx => `Цена бумаги: ${ctx.parsed.y} ₽`, footer: items => { const i = items[0].dataIndex; return `НКД на дату: ${currentBondNkd[i]} ₽\nДоходность YTM: ${currentBondYtm[i]} %`; } } }, zoom: { pan: { enabled: true, mode: 'x' }, zoom: { wheel: { enabled: true }, pinch: { enabled: true }, mode: 'x' } } } } }); } function applyChartScale(period, ev) { if (ev && ev.target && ev.target.classList.contains('btn')) { document.querySelectorAll('#periodBtnGroup .btn').forEach(b => b.classList.remove('active')); ev.target.classList.add('active'); } loadBondChartData(period); } async function loadDashboard() { await fetchActivePortfolio(); fetchChartAnalytics(); fetchCouponCalendar(); fetchIncomeWidget(); } async function fetchCouponCalendar() { const response = await fetch('/api/portfolio/calendar'); if (!response.ok) return; const events = await response.json(); const list = document.getElementById('coupon-calendar-list'); list.innerHTML = ''; if (events.length === 0) { list.innerHTML = '<li class="list-group-item text-center text-muted py-3">Нет предстоящих купонов.</li>'; return; } const esc = window.Common.escapeHtml; events.forEach(e => { list.innerHTML += ` <li class="list-group-item d-flex justify-content-between align-items-center"> <div><b>${esc(e.name)}</b><br><small class="text-muted">${esc(e.date)}</small></div> <span class="badge bg-success font-monospace">+ ${parseFloat(e.total_payout).toFixed(2)} ₽</span> </li>`; }); } function sortTable(key) { if (sortKey === key) sortDir = -sortDir; else { sortKey = key; sortDir = 1; } renderBondRows(); _updateSortIndicators(); } function _updateSortIndicators() { document.querySelectorAll('.sort-icon').forEach(el => { const col = el.dataset.col; el.textContent = col === sortKey ? (sortDir === 1 ? ' ↑' : ' ↓') : ''; }); } function _skeletonRows(cols = 9, rows = 4) { let html = ''; const widths = ['60%', '30%', '20%', '25%', '20%', '20%', '20%', '30%', '15%']; for (let r = 0; r < rows; r++) { html += '<tr>'; for (let c = 0; c < cols; c++) { const w = widths[c] || '30%'; html += `<td><span class="skeleton-cell" style="width:${w}"></span></td>`; } html += '</tr>'; } return html; } async function fetchActivePortfolio() { const tbody = document.getElementById('bonds-table-body'); tbody.innerHTML = _skeletonRows(); const response = await fetch('/api/portfolio'); if (response.status === 401) { window.location.href = '/'; return; } const data = await response.json(); document.getElementById('total-portfolio-value').innerText = data.total_value.toLocaleString('ru-RU', { minimumFractionDigits: 2 }); const ytmEl = document.getElementById('portfolio-ytm'); if (ytmEl) ytmEl.textContent = data.portfolio_ytm ? data.portfolio_ytm.toFixed(2) + ' %' : '—'; const countEl = document.getElementById('portfolio-count'); if (countEl) countEl.textContent = (data.bonds || []).length; bondsData = data.bonds || []; renderBondRows(); renderAllocationChart(); } function _renderBondRow(bond, esc, isSubRow) { const pnl = bond.pnl ?? 0; const pnlPct = bond.pnl_pct ?? 0; const pnlClass = pnl >= 0 ? 'text-success' : 'text-danger'; const sign = pnl >= 0 ? '+' : ''; const noteClass = bond.notes ? ' note-filled' : ''; const noteTip = bond.notes ? 'Редактировать заметку' : 'Добавить заметку'; const subStyle = isSubRow ? ' style="background:var(--surface-0);font-size:.88rem"' : ''; const namePrefix = isSubRow ? `<span style="color:var(--text-tertiary);margin-right:.3rem">•</span>` : ''; const dateSuffix = isSubRow ? ` <small style="color:var(--text-tertiary)">${esc(bond.purchase_date || '')}</small>` : ''; return ` <tr data-name